CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE tenants (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, slug text NOT NULL UNIQUE, status text NOT NULL DEFAULT 'active', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE tenant_settings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL UNIQUE REFERENCES tenants(id), settings jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE users (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), email text NOT NULL UNIQUE, display_name text NOT NULL, subject text UNIQUE, actor_type text NOT NULL DEFAULT 'internal_user', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE tenant_memberships (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), user_id uuid NOT NULL REFERENCES users(id), status text NOT NULL DEFAULT 'active', member_type text NOT NULL DEFAULT 'internal', created_by uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,user_id));
CREATE INDEX tenant_memberships_tenant_id_status_idx ON tenant_memberships(tenant_id,status);
CREATE TABLE roles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid REFERENCES tenants(id), code text NOT NULL, name text NOT NULL, description text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,code));
CREATE TABLE permissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text NOT NULL UNIQUE, description text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE role_permissions (role_id uuid NOT NULL REFERENCES roles(id), permission_id uuid NOT NULL REFERENCES permissions(id), created_at timestamptz NOT NULL DEFAULT now(), PRIMARY KEY(role_id,permission_id));
CREATE TABLE user_role_assignments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), user_id uuid NOT NULL REFERENCES users(id), role_id uuid NOT NULL REFERENCES roles(id), scope_type text NOT NULL DEFAULT 'tenant', scope_id uuid, created_by uuid, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,user_id,role_id,scope_type,scope_id));
CREATE TABLE organization_units (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), code text NOT NULL, name text NOT NULL, parent_id uuid, created_by uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,code));
CREATE TABLE cost_centers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), code text NOT NULL, name text NOT NULL, active boolean NOT NULL DEFAULT true, created_by uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,code));
CREATE TABLE locations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), code text NOT NULL, name text NOT NULL, address jsonb, created_by uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(tenant_id,code));
CREATE TABLE audit_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid REFERENCES tenants(id), actor_id uuid, action text NOT NULL, object_type text NOT NULL, object_id uuid, correlation_id text NOT NULL, metadata jsonb, prior_state jsonb, resulting_state jsonb, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX audit_events_tenant_id_created_at_idx ON audit_events(tenant_id,created_at);
CREATE TABLE file_objects (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), storage_key text NOT NULL UNIQUE, filename text NOT NULL, mime_type text NOT NULL, size_bytes bigint NOT NULL, checksum_sha256 text NOT NULL, uploader_id uuid NOT NULL REFERENCES users(id), classification text NOT NULL, upload_state text NOT NULL DEFAULT 'pending', scan_status text NOT NULL DEFAULT 'pending', retention_until timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX file_objects_tenant_id_upload_state_idx ON file_objects(tenant_id,upload_state);
CREATE TABLE file_links (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL REFERENCES tenants(id), file_object_id uuid NOT NULL REFERENCES file_objects(id), object_type text NOT NULL, object_id uuid NOT NULL, created_by uuid, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX file_links_tenant_id_object_type_object_id_idx ON file_links(tenant_id,object_type,object_id);
CREATE OR REPLACE FUNCTION current_tenant_id() RETURNS uuid LANGUAGE sql STABLE AS $$ SELECT NULLIF(current_setting('app.current_tenant_id', true),'')::uuid $$;
CREATE OR REPLACE FUNCTION prevent_audit_mutation() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN RAISE EXCEPTION 'audit_events are append-only'; END; $$;
CREATE TRIGGER audit_events_no_update BEFORE UPDATE OR DELETE ON audit_events FOR EACH ROW EXECUTE FUNCTION prevent_audit_mutation();
DO $$ DECLARE t text; BEGIN FOREACH t IN ARRAY ARRAY['tenant_settings','tenant_memberships','roles','user_role_assignments','organization_units','cost_centers','locations','audit_events','file_objects','file_links'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', t); EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY', t); EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id = current_tenant_id()) WITH CHECK (tenant_id = current_tenant_id())', t); END LOOP; END $$;
INSERT INTO permissions(code,description) VALUES ('tenant.manage','Manage tenant platform foundation settings'),('tenant.members.manage','Manage tenant memberships'),('roles.manage','Manage tenant roles and permission assignments'),('audit.read','Read tenant audit events'),('files.read','Read authorized tenant file metadata'),('files.write','Create authorized tenant file metadata');
